// ===== 首页数据更新 =====
function updateHomePage() {
  // 问候语
  const h = new Date().getHours();
  const greetingEl = document.getElementById('greeting-text');
  const subEl = document.getElementById('greeting-sub');
  if (greetingEl && subEl) {
    if (h < 12) { greetingEl.textContent = '☀️ 早上好，永远的神！'; subEl.textContent = '新的一天，充满能量 💪'; }
    else if (h < 18) { greetingEl.textContent = '🌤️ 下午好，永远的神！'; subEl.textContent = '下午也要加油哦 💪'; }
    else { greetingEl.textContent = '🌙 晚上好，永远的神！'; subEl.textContent = '今天学到了什么？'; }
  }

  // 等级
  const done = (store.doneUnits || []).length + (store.doneOM || []).length;
  const level = Math.floor(done / 3) + 1;
  const levelNum = document.getElementById('level-num');
  if (levelNum) levelNum.textContent = level;

  // 能量条
  const totalTasks = 4;
  const todayKey = 'shengrong_v6_today_' + new Date().toDateString();
  const todayTasks = JSON.parse(localStorage.getItem(todayKey)) || {};
  const doneTasks = Object.values(todayTasks).filter(Boolean).length;
  const pct = Math.round((doneTasks / totalTasks) * 100);
  const fill = document.getElementById('energy-fill');
  const pctEl = document.getElementById('energy-pct');
  if (fill) fill.style.width = pct + '%';
  if (pctEl) pctEl.textContent = pct + '%';

  // 今日任务勾选
  const taskMap = { poem: 'tw-poem', math: 'tw-math', english: 'tw-english', diary: 'tw-diary' };
  const taskLabels = { poem: '📖', math: '📐', english: '🔤', diary: '✍️' };
  Object.keys(taskMap).forEach(k => {
    const el = document.getElementById(taskMap[k]);
    if (!el) return;
    const done = !!todayTasks[k];
    el.classList.toggle('done', done);
    el.querySelector('.tw-check').textContent = done ? '✓' : '○';
  });
  const twTextEl = document.getElementById('tw-progress-text');
  if (twTextEl) twTextEl.textContent = doneTasks + '/' + totalTasks;

  // 三大入口进度
  const learnCount = (store.doneUnits || []).length;
  const learnTotal = 28;
  const learnBar = document.getElementById('qe-learn-bar');
  const learnCountEl = document.getElementById('qe-learn-count');
  if (learnBar) learnBar.style.width = Math.round(learnCount/learnTotal*100) + '%';
  if (learnCountEl) learnCountEl.textContent = learnCount + ' 已完成';

  const shineCount = (store.diary || []).length;
  const shineCountEl = document.getElementById('qe-shine-count');
  if (shineCountEl) shineCountEl.textContent = shineCount + '篇日记';

  const techCount = (store.news || []).length;
  const techCountEl = document.getElementById('qe-tech-count');
  if (techCountEl) techCountEl.textContent = techCount + ' 条新闻';

  // 首页底部照片滚动
  const photoScroll = document.getElementById('hb-photo-scroll');
  if (photoScroll) {
    if (!store.shines || !store.shines.length) {
      photoScroll.innerHTML = `<div style="padding:16px;text-align:center;color:#8b949e;font-size:12px;">还没有照片<br><span style="font-size:11px;color:#58a6ff;cursor:pointer;" onclick="goPage('shine')">去闪光时刻上传 →</span></div>`;
    } else {
      const photos = store.shines.slice(0, 8);
      photoScroll.innerHTML = photos.map(s => `
        <div class="hb-photo-item" onclick='goPage("shine")'>
          ${s.img ? `<img src="${s.img}" alt="${s.title}">` : `<div class="hb-photo-placeholder" style="background:${s.bgColor||'#eee'}">${s.icon}</div>`}
          <div class="hp-caption">${s.title}</div>
        </div>`).join('');
    }
  }

  // 首页底部科技新闻
  const newsListEl = document.getElementById('hb-news-list');
  if (newsListEl) {
    if (!store.news || !store.news.length) {
      newsListEl.innerHTML = `<div style="padding:16px;text-align:center;color:#8b949e;font-size:12px;">还没有新闻<br><span style="font-size:11px;color:#58a6ff;cursor:pointer;" onclick="goPage('tech')">去科技新闻添加 →</span></div>`;
    } else {
      const news = store.news.slice(0, 4);
      const icons = { ai:'🤖', space:'🚀', robot:'🤖', tech:'💡', game:'🎮' };
      newsListEl.innerHTML = news.map(n => `
        <div class="hb-news-item" onclick="goPage('tech')">
          <span class="hb-news-icon">${n.icon || icons[n.type] || '🔭'}</span>
          <span class="hb-news-title">${n.title}</span>
          <span class="hb-news-date">${n.date || ''}</span>
        </div>`).join('');
    }
  }
}



// ===== 侧边栏收起/展开 =====
function toggleSidebar() {
  const sidebar = document.getElementById('sidebar');
  const toggle = document.getElementById('sidebar-toggle');
  const main = document.getElementById('main-content');
  const music = document.getElementById('music-player');
  sidebar.classList.toggle('collapsed');
  const collapsed = sidebar.classList.contains('collapsed');
  toggle.textContent = collapsed ? '☰' : '✕';
  toggle.title = collapsed ? '展开菜单' : '收起菜单';
  if (main) main.style.paddingLeft = collapsed ? '84px' : '230px';
  if (music) music.style.left = collapsed ? '64px' : '210px';
}


// ===== 导航 =====
function goPage(page) {
  document.querySelectorAll('.nav-item').forEach(i => i.classList.remove('active'));
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelector(`.nav-item[data-page="${page}"]`).classList.add('active');
  document.getElementById('page-' + page).classList.add('active');
  window.scrollTo(0, 0);
}
document.querySelectorAll('.nav-item').forEach(item => {
  item.addEventListener('click', () => goPage(item.dataset.page));
});

