function renderEnglishWords() {
  const container = document.getElementById('english-words-grid');
  if (!container) return;
  
  // 按 Unit 分组显示，默认显示 Unit 1
  const units = Object.keys(ENGLISH_WORDS);
  
  // 渲染单元标签
  let tabsHtml = '<div class="filter-pills" id="ew-tabs">';
  units.forEach((u, i) => {
    tabsHtml += `<span class="filter-pill ${i===0?'active':''}" onclick="showWordUnit('${u}', this)">${u}</span>`;
  });
  tabsHtml += '</div>';
  
  // 渲染词汇表格
  let tableHtml = '';
  units.forEach((u, i) => {
    tableHtml += `<div class="ew-unit ${i===0?'':'hidden'}" id="ew-unit-${u.replace(' ','-')}">
      <div class="ew-grid">`;
    ENGLISH_WORDS[u].forEach(w => {
      tableHtml += `<div class="ew-card">
        <div class="ew-word">${w.word}</div>
        <div class="ew-zh">${w.zh}</div>
        <div class="ew-sentence">${w.sentence}</div>
      </div>`;
    });
    tableHtml += '</div></div>';
  });
  
  container.innerHTML = tabsHtml + tableHtml;
}

function showWordUnit(unit, el) {
  document.querySelectorAll('#ew-tabs .filter-pill').forEach(p => p.classList.remove('active'));
  el.classList.add('active');
  document.querySelectorAll('.ew-unit').forEach(u => u.classList.add('hidden'));
  document.getElementById('ew-unit-' + unit.replace(' ','-')).classList.remove('hidden');
}


function renderLearn() {
  Object.values(SUBJECTS).forEach(sub => {
    const grid = document.getElementById(sub.title);
    grid.innerHTML = sub.data.map((u, i) => {
      const key = sub.title + '_' + i;
      const done = store.doneUnits.includes(key);
      return `<div class="unit-card ${done?'done':''}" onclick="toggleUnit('${key}')">
        <div class="unit-card-header"><span class="unit-card-title">${u.name}</span></div>
        <div class="unit-card-meta">${u.sub}</div>
      </div>`;
    }).join('');
  });
  renderPoems();
  renderOM();
  renderEnglishWords();
}

function toggleUnit(key) {
  if (store.doneUnits.includes(key)) store.doneUnits = store.doneUnits.filter(k => k !== key);
  else store.doneUnits.push(key);
  saveStore(); renderLearn(); updateHomePage();
}

