function renderOM() {
  const grid = document.getElementById('olympiad-grid');
  grid.innerHTML = OM_TOPICS.map(t => {
    const done = store.doneOM.includes(t.id);
    const tagColor = ['blue','pink','yellow','purple','blue','pink','yellow','purple','blue'][t.id];
    return `<div class="om-card ${done?'done':''}" onclick="showOM(${t.id})">
      <div class="om-title">
        ${t.name}
        <span class="om-done">${done?'✅':'📝'}</span>
      </div>
      <div class="om-tags">
        <span class="tag ${tagColor}">${t.tag}</span>
        ${done ? '<span class="tag done">已掌握</span>' : ''}
      </div>
      <div class="om-meta">${t.problem.substring(0,25)}...</div>
    </div>`;
  }).join('');
}

function showOM(id) {
  const t = OM_TOPICS.find(x => x.id === id);
  if (!t) return;
  const done = store.doneOM.includes(id);
  const tagColor = ['blue','pink','yellow','purple','blue','pink','yellow','purple','blue'][id];
  document.getElementById('detail-body').innerHTML = `
    <div class="om-problem-box">
      <h4>📝 ${t.name} · ${t.tag}</h4>
      <p>${t.problem}</p>
    </div>
    <div class="om-answer-box">
      <h4>💡 解答方法</h4>
      <p>${t.method}</p>
      <p style="margin-top:8px;"><strong>答案：</strong>${t.answer}</p>
    </div>
    <div class="form-actions" style="margin-top:16px;">
      <button class="btn ${done?'':'btn-primary'}" onclick="toggleOM(${id})">
        ${done?'↩️ 取消已掌握':'✅ 我会了'}
      </button>
      <button class="btn" onclick="closeModal('modal-detail')">关闭</button>
    </div>`;
  openModal('modal-detail');
}

function toggleOM(id) {
  if (store.doneOM.includes(id)) store.doneOM = store.doneOM.filter(k => k !== id);
  else store.doneOM.push(id);
  saveStore(); renderOM(); updateHomePage(); showOM(id);
}



