// ===== 照片灯箱 =====
let currentPhotoIndex = 0;
let photoList = [];

function openPhotoLightbox(photoIdx) {
  photoList = store.shines.filter(s => s.img).map(s => ({ src: s.img, title: s.title, date: s.date }));
  currentPhotoIndex = photoIdx;
  if (currentPhotoIndex < 0 || currentPhotoIndex >= photoList.length) currentPhotoIndex = 0;
  showPhotoInLightbox(currentPhotoIndex);
  document.getElementById('photo-lightbox').classList.add('active');
  document.body.style.overflow = 'hidden';
}

function showPhotoInLightbox(idx) {
  const s = photoList[idx];
  if (!s) return;
  document.getElementById('plb-img').src = s.src;
  document.getElementById('plb-caption').textContent = s.title;
  document.getElementById('plb-date').textContent = s.date;
  // 更新导航点
  const nav = document.getElementById('plb-nav');
  nav.innerHTML = photoList.map((_, i) => `<div class="plb-dot ${i===idx?'active':''}" onclick="event.stopPropagation(); showPhotoInLightbox(${i})"></div>`).join('');
  currentPhotoIndex = idx;
}

function closePhotoLightbox(event) {
  if (event && event.target !== event.currentTarget && !event.target.classList.contains('plb-close')) return;
  document.getElementById('photo-lightbox').classList.remove('active');
  document.body.style.overflow = '';
}

document.addEventListener('keydown', function(e) {
  if (!document.getElementById('photo-lightbox').classList.contains('active')) return;
  if (e.key === 'Escape') closePhotoLightbox(e);
  if (e.key === 'ArrowLeft') showPhotoInLightbox((currentPhotoIndex - 1 + photoList.length) % photoList.length);
  if (e.key === 'ArrowRight') showPhotoInLightbox((currentPhotoIndex + 1) % photoList.length);
});


// ===== 背景音乐 =====
let isPlaying = false;
const bgAudio = document.getElementById('bg-audio');
const musicPlayBtn = document.getElementById('music-play-btn');
const musicIcon = document.getElementById('music-icon');
const musicName = document.getElementById('music-name');

function toggleMusic() {
  if (!bgAudio.src) { alert('请先上传吉他演奏音乐！'); return; }
  if (isPlaying) {
    bgAudio.pause();
    musicPlayBtn.textContent = '▶';
    musicIcon.classList.remove('playing');
  } else {
    bgAudio.play();
    musicPlayBtn.textContent = '⏸';
    musicIcon.classList.add('playing');
  }
  isPlaying = !isPlaying;
}

function uploadMusic(input) {
  const file = input.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(e) {
    bgAudio.src = e.target.result;
    bgAudio.volume = 0.6;
    musicName.textContent = file.name.replace(/\.[^.]+$/, '');
    bgAudio.play();
    isPlaying = true;
    musicPlayBtn.textContent = '⏸';
    musicIcon.classList.add('playing');
    // 存到localStorage
    try { localStorage.setItem('shengrong_bgmusic', e.target.result); } catch(e) {}
  };
  reader.readAsDataURL(file);
}

// 页面加载时恢复音乐
document.addEventListener('DOMContentLoaded', function() {
  try {
    const saved = localStorage.getItem('shengrong_bgmusic');
    if (saved) {
      bgAudio.src = saved;
      bgAudio.volume = 0.6;
      musicName.textContent = '吉他演奏 🎸';
    }
  } catch(e) {}
});



