function renderPhotoWall() {
    const wall = document.getElementById('photowall');
    if (!wall) { console.log('[PW] photowall element not found'); return; }
    const photos = store.shines.filter(s => s.photo || s.img);
    console.log('[PW] Found', photos.length, 'photos with base64, IDs:', photos.map(p => p.id).join(','));
    
    wall.innerHTML = '';
    
    if (photos.length === 0) {
        wall.innerHTML = '<div style="text-align:center;padding:60px;color:var(--text2)"><div style="font-size:48px;opacity:0.4">📷</div><p style="opacity:0.6">还没有照片</p></div>';
        return;
    }
    
    wall.style.display = 'flex';
    wall.style.flexWrap = 'wrap';
    wall.style.gap = '16px';
    wall.style.padding = '16px';
    
    photos.forEach((p) => {
        const photoSrc = p.photo || p.img || '';
        const el = document.createElement('div');
        el.style.cssText = 'flex:0 0 calc(33.33% - 12px);min-width:120px;max-width:200px;cursor:pointer;position:relative;padding-top:8px';
        el.innerHTML = '<img src="' + photoSrc + '" alt="' + p.title + '" style="width:100%;border-radius:8px;box-shadow:0 2px 8px rgba(0,0,0,0.15)" onclick="openLightbox(\'' + photoSrc.replace(/'/g, "\\'") + '\')"><div style="text-align:center;font-size:12px;margin-top:4px;color:var(--text2);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + p.title + '</div>';
        wall.appendChild(el);
    });
}
/* 3D鼠标追踪效果 */
function pw3D(el, e) {
  var rect = el.getBoundingClientRect();
  var x = (e.clientX - rect.left) / rect.width;
  var y = (e.clientY - rect.top) / rect.height;
  var rotateY = (x - 0.5) * 20;
  var rotateX = (0.5 - y) * 20;
  el.style.setProperty('--mx', (x*100)+'%');
  el.style.setProperty('--my', (y*100)+'%');
  el.style.transform = 'translateY(-8px) scale(1.04) rotateX('+rotateX+'deg) rotateY('+rotateY+'deg)';
}
function pw3DReset(el) {
  el.style.transform = '';
  el.style.setProperty('--mx', '50%');
  el.style.setProperty('--my', '50%');
}

